Here's a minimal API endpoint that handles multipart form uploads with multiple images and a description:

```csharp
// Program.cs

var builder = WebApplication.CreateBuilder(args);

// Raise the max request body size (default is ~30 MB)
builder.WebHost.ConfigureKestrel(o => o.Limits.MaxRequestBodySize = 50 * 1024 * 1024);

var app = builder.Build();

app.MapPost("/upload", async (HttpRequest request) =>
{
    // Read the multipart form with a 50 MB limit
    var form = await request.ReadFormAsync(new FormOptions
    {
        MultipartBodyLengthLimit = 50L * 1024 * 1024
    });

    var description = form["description"].ToString();
    var files = form.Files.GetFiles("images");

    if (files.Count == 0)
        return Results.BadRequest("No images provided.");

    var saved = new List<string>();

    foreach (var file in files)
    {
        // Validate content type
        if (!file.ContentType.StartsWith("image/"))
            return Results.BadRequest($"'{file.FileName}' is not an image.");

        var dest = Path.Combine("uploads", $"{Guid.NewGuid()}{Path.GetExtension(file.FileName)}");
        Directory.CreateDirectory("uploads");

        await using var stream = File.Create(dest);
        await file.CopyToAsync(stream);
        saved.Add(dest);
    }

    return Results.Ok(new { description, uploadedFiles = saved });
})
.DisableAntiforgery();          // required for form POSTs without a token
                                 // (remove if you wire up antiforgery)

app.Run();
```

**Test it with `curl`:**

```bash
curl -X POST http://localhost:5000/upload \
  -F "description=My vacation photos" \
  -F "images=@photo1.jpg" \
  -F "images=@photo2.png"
```

**Key points:**

- **Kestrel limit** — `MaxRequestBodySize` must be raised; it defaults to ~28.6 MB.
- **`FormOptions.MultipartBodyLengthLimit`** — separate cap on multipart body parsing.
- **`DisableAntiforgery()`** — needed in .NET 8+ for anonymous form POSTs (it's now enforced by default).
- The form field names (`description`, `images`) must match what the client sends.

If you're behind IIS/IIS Express, also add to `web.config`:

```xml
<system.webServer>
  <security>
    <requestFiltering>
      <requestLimits maxAllowedContentLength="52428800" />
    </requestFiltering>
  </security>
</system.webServer>
```
